import json
import boto3

def lambda_handler(event, context):
    # Validate input
    if 'key' not in event or not isinstance(event['key'], str):
        raise ValueError("Invalid input: 'key' is required and must be a string.")

    # Use secure platform APIs
    s3_client = boto3.client('s3')
    dynamodb_client = boto3.client('dynamodb')
    sns_client = boto3.client('sns')
    sqs_client = boto3.client('sqs')

    # Example operation: Get an object from S3
    try:
        response = s3_client.get_object(Bucket='your-bucket-name', Key=event['key'])
        data = response['Body'].read()
    except Exception as e:
        raise RuntimeError(f"Error accessing S3: {str(e)}")

    # Example operation: Put an item in DynamoDB
    try:
        dynamodb_client.put_item(
            TableName='your-table-name',
            Item={
                'PrimaryKey': {'S': event['key']},
                'Data': {'S': data.decode('utf-8')}
            }
        )
    except Exception as e:
        raise RuntimeError(f"Error accessing DynamoDB: {str(e)}")

    # Example operation: Publish a message to SNS
    try:
        sns_client.publish(
            TopicArn='arn:aws:sns:region:account-id:your-topic-name',
            Message='New data processed',
            Subject='Data Update'
        )
    except Exception as e:
        raise RuntimeError(f"Error publishing to SNS: {str(e)}")

    # Example operation: Send a message to SQS
    try:
        sqs_client.send_message(
            QueueUrl='https://sqs.region.amazonaws.com/account-id/your-queue-name',
            MessageBody='Data processed successfully'
        )
    except Exception as e:
        raise RuntimeError(f"Error sending message to SQS: {str(e)}")

    return {
        'statusCode': 200,
        'body': json.dumps('Operation completed successfully')
    }